 1	import React, { Dispatch, FC, SetStateAction, useMemo, useState } from 'react';
 2	
 3	import { InstanceTypes } from '@catalog/CreateFromInstanceTypes/state/utils/types';
 4	import { VirtualMachineInstancetypeModelGroupVersionKind } from '@kubevirt-ui/kubevirt-api/console';
 5	import { isRedHatInstanceType } from '@kubevirt-utils/components/AddBootableVolumeModal/components/VolumeMetadata/components/InstanceTypeDrilldownSelect/utils/utils';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { VirtualMachineClusterInstancetypeModelGroupVersionKind } from '@kubevirt-utils/models';
 8	import { getName } from '@kubevirt-utils/resources/shared';
 9	import { isEmpty } from '@kubevirt-utils/utils/utils';
10	import { ResourceIcon } from '@openshift-console/dynamic-plugin-sdk';
11	import { MenuItem, MenuSearch, MenuSearchInput, SearchInput } from '@patternfly/react-core';
12	
13	type UserInstanceTypeMenuProps = {
14	  allInstanceTypes: InstanceTypes;
15	  selected: string;
16	  setSelected: Dispatch<SetStateAction<string>>;
17	};
18	
19	const UserInstanceTypeMenu: FC<UserInstanceTypeMenuProps> = ({
20	  allInstanceTypes,
21	  selected,
22	  setSelected,
23	}) => {
24	  const { t } = useKubevirtTranslation();
25	
26	  const [searchInput, setSearchInput] = useState('');
27	
28	  const userCreatedInstanceTypes = allInstanceTypes.filter((it) => !isRedHatInstanceType(it));
29	
30	  const filteredItems = useMemo(
31	    () =>
32	      userCreatedInstanceTypes.filter(
33	        (it) =>
34	          isEmpty(searchInput) ||
35	          getName(it).toLowerCase().includes(searchInput.toString().toLowerCase()),
36	      ),
37	    [userCreatedInstanceTypes, searchInput],
38	  );
39	
40	  if (isEmpty(filteredItems)) return <MenuItem isDisabled>{t('No results found')}</MenuItem>;
41	
42	  return (
43	    <>
44	      {filteredItems.length > 5 && (
45	        <MenuSearch>
46	          <MenuSearchInput>
47	            <SearchInput
48	              aria-label="Filter menu items"
49	              onChange={(_, value) => setSearchInput(value)}
50	              type="search"
51	              value={searchInput}
52	            />
53	          </MenuSearchInput>
54	        </MenuSearch>
55	      )}
56	      {filteredItems.map((it) => {
57	        const itName = getName(it);
58	        return (
59	          <MenuItem
60	            icon={
61	              <ResourceIcon
62	                groupVersionKind={
63	                  it?.kind === 'VirtualMachineClusterInstancetype'
64	                    ? VirtualMachineClusterInstancetypeModelGroupVersionKind
65	                    : VirtualMachineInstancetypeModelGroupVersionKind
66	                }
67	              />
68	            }
69	            isSelected={selected === itName}
70	            itemId={itName}
71	            key={itName}
72	            onClick={() => setSelected(itName)}
73	          >
74	            {itName}
75	          </MenuItem>
76	        );
77	      })}
78	    </>
79	  );
80	};
81	export default UserInstanceTypeMenu;

